mkdir -p /app/src
cat > /app/src/server.ts <<'BUN_BENCH_SOLUTION_EOF'
import { randomUUID } from "node:crypto";

const port = Number(Bun.env.PORT ?? 3000);

type Status = "queued" | "running" | "retrying" | "succeeded" | "dead_letter";

type Job = {
  id: string;
  type: string;
  status: Status;
  attempts: number;
  max_attempts: number;
  last_error?: string;
};

const MAX_ATTEMPTS = 3;
const jobs = new Map<string, Job>();

function isTerminal(status: Status): boolean {
  return status === "succeeded" || status === "dead_letter";
}

// Deterministic processing outcome. Returns true on success.
// `attempt` is the 1-based attempt number being executed.
function runJob(type: string, attempt: number): boolean {
  switch (type) {
    case "ok":
      return true;
    case "flaky":
      return attempt >= 3;
    case "fail":
    default:
      return false;
  }
}

function backoffMs(attempt: number): number {
  // Small, growing backoff: 20ms, 40ms, ... kept tiny so tests finish fast.
  return 20 * attempt;
}

function schedule(job: Job, delay: number): void {
  setTimeout(() => process(job.id), delay);
}

function process(id: string): void {
  const job = jobs.get(id);
  if (!job) return;
  // Terminal jobs are never reprocessed.
  if (isTerminal(job.status)) return;
  // Guard against an already-running job being picked up twice.
  if (job.status === "running") return;

  job.status = "running";
  const attempt = job.attempts + 1;
  let ok = false;
  try {
    ok = runJob(job.type, attempt);
  } catch {
    ok = false;
  }
  job.attempts = attempt;

  if (ok) {
    job.status = "succeeded";
    return;
  }

  job.last_error = `attempt ${attempt} failed for type "${job.type}"`;
  if (job.attempts >= job.max_attempts) {
    job.status = "dead_letter";
    return;
  }
  job.status = "retrying";
  schedule(job, backoffMs(job.attempts));
}

function publicJob(job: Job): Record<string, unknown> {
  const out: Record<string, unknown> = {
    id: job.id,
    type: job.type,
    status: job.status,
    attempts: job.attempts,
    max_attempts: job.max_attempts,
  };
  if (job.last_error !== undefined) out.last_error = job.last_error;
  return out;
}

Bun.serve({
  port,
  async fetch(request) {
    const url = new URL(request.url);
    const segments = url.pathname.split("/").filter(Boolean);

    if (request.method === "POST" && url.pathname === "/jobs") {
      let body: unknown;
      try {
        body = await request.json();
      } catch {
        return Response.json({ error: "invalid_json" }, { status: 400 });
      }
      const record = body as Record<string, unknown> | null;
      if (!record || typeof record.type !== "string") {
        return Response.json({ error: "invalid_body" }, { status: 422 });
      }
      const job: Job = {
        id: randomUUID(),
        type: record.type,
        status: "queued",
        attempts: 0,
        max_attempts: MAX_ATTEMPTS,
      };
      jobs.set(job.id, job);
      // Process asynchronously, decoupled from this request.
      schedule(job, 0);
      return Response.json(
        { id: job.id, status: "queued", attempts: 0, max_attempts: MAX_ATTEMPTS },
        { status: 201 },
      );
    }

    if (segments.length === 2 && segments[0] === "jobs" && request.method === "GET") {
      const job = jobs.get(segments[1]!);
      if (!job) return Response.json({ error: "not_found" }, { status: 404 });
      return Response.json(publicJob(job), { status: 200 });
    }

    return Response.json({ error: "not_found" }, { status: 404 });
  },
});

console.log(`retry-queue reference listening on ${port}`);
BUN_BENCH_SOLUTION_EOF
